fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let mut nums = nums;
    nums.sort();
    let n = nums.len();
    let mut min_removal = (n - 1) as i64; // worst case: keep only one element

    for i in 0..n {
        let min_val = nums[i];
        let target = min_val * k;
        let j = match nums.binary_search(&target) {
            Ok(pos) => pos + 1,
            Err(pos) => pos,
        };
        let keep = (j - i) as i64;
        min_removal = std::cmp::min(min_removal, n as i64 - keep);
    }

    min_removal
}
